PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT DISTINCT ?disease_label ?omim ?orpha_id WHERE {
  GRAPH <urn:doid> {
    ?disease oboInOwl:hasDbXref ?mim ;
             oboInOwl:hasDbXref ?orpha_id ;
             rdfs:label ?disease_label .
    FILTER(STRSTARTS(STR(?mim), "MIM:"))
    FILTER(CONTAINS(STR(?orpha_id), "orpha.net"))
  }
  BIND(REPLACE(STR(?mim), "^MIM:", "OMIM:") AS ?omim)
  BIND(STR(?orpha_id) AS ?orpha_id)
}

