    ?disease rdfs:subClassOf+ obo:DOID_0014667 ;
             rdfs:label ?doid_label ;
             oboInOwl:hasDbXref ?orpha_xref .
    FILTER(CONTAINS(STR(?orpha_xref), "orpha.net"))
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?disease ?label WHERE {
  GRAPH <urn:doid> {
    ?disease a owl:Class ;
             rdfs:label ?label .
    FILTER NOT EXISTS {
      ?disease obo:IAO_0000115 ?definition .
    }
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>

SELECT ?label ?hasSynonym WHERE {
  GRAPH <urn:doid> {
    ?disease rdfs:subClassOf obo:DOID_863 ;
             rdfs:label ?label .
    OPTIONAL {
      ?disease oboInOwl:hasExactSynonym ?hasSynonym .
    }
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?source_id ?disease_name WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id ?source_id ;
             rdfs:label ?disease_name .
    FILTER(STRSTARTS(?source_id, "OMIM:"))
  }
  BIND(REPLACE(?source_id, "^OMIM:", "MIM:") AS ?mim_id)
  OPTIONAL {
    GRAPH <urn:doid> {
      ?doid_class oboInOwl:hasDbXref ?mim_id .
    }
  }
  FILTER(!BOUND(?doid_class))
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?pheno_label WHERE {
  GRAPH <urn:hpo> {
    ?pheno rdfs:subClassOf+ obo:HP_0000478 ;
           rdfs:label ?pheno_label .
  }
  FILTER NOT EXISTS {
    GRAPH <urn:hpoa> {
      ?disease hpoa:has_phenotype ?pheno .
    }
  }
} LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
SELECT ?source ?label WHERE {
  {
    GRAPH <urn:doid> {
      obo:DOID_2841 rdfs:label ?label .
    }
    BIND("DOID" AS ?source)
  }
  UNION
  {
    GRAPH <urn:hpo> {
      ?term rdfs:label ?label .
      FILTER(LCASE(?label) = "asthma")
    }
    BIND("HPO" AS ?source)
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?source ?term ?label WHERE {
  {
    GRAPH <urn:doid> {
      ?term rdfs:label ?label .
      FILTER(CONTAINS(LCASE(?label), "epilepsy"))
    }
    BIND("DOID" AS ?source)
  }
  UNION
  {
    GRAPH <urn:hpo> {
      ?term rdfs:label ?label .
      FILTER(CONTAINS(LCASE(?label), "epilepsy"))
    }
    BIND("HPO" AS ?source)
  }
} LIMIT 30

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>

SELECT ?type ?value WHERE {
  {
    GRAPH <urn:doid> {
      ?disease oboInOwl:hasDbXref "MIM:141900" .
      BIND(REPLACE(STR(?disease), "^obo:DOID_", "obo:DOID_") AS ?disease_uri)
      BIND(REPLACE(STR(?disease_uri), "MIM:141900", "OMIM:141900") AS ?omim)
      ?disease oboInOwl:hasExactSynonym ?value .
      BIND("synonym" AS ?type)
    }
  }
  UNION
  {
    GRAPH <urn:doid> {
      ?disease oboInOwl:hasDbXref "MIM:141900" .
      BIND(REPLACE(STR(?disease), "^obo:DOID_", "obo:DOID_") AS ?disease_uri)
      BIND(REPLACE(STR(?disease_uri), "MIM:141900", "OMIM:141900") AS ?omim)
      ?disease obo:IAO_0000115 ?value .
      BIND("definition" AS ?type)
    }
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT DISTINCT ?disease_name ?category WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno ;
             rdfs:label ?disease_name .
  }
  {
    GRAPH <urn:hpo> {
      ?pheno rdfs:subClassOf+ obo:HP_0000707 .
    }
    BIND("nervous system" AS ?category)
  }
  UNION
  {
    GRAPH <urn:hpo> {
      ?pheno rdfs:subClassOf+ obo:HP_0001626 .
    }
    BIND("cardiovascular" AS ?category)
  }
} LIMIT 30

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?disease_name ?cnt WHERE {
  {
    SELECT ?disease ?disease_name (COUNT(DISTINCT ?pheno) AS ?cnt) WHERE {
      GRAPH <urn:hpoa> {
        ?disease hpoa:has_phenotype ?pheno ;
                 rdfs:label ?disease_name .
      }
    } GROUP BY ?disease ?disease_name
  }
  {
    SELECT (AVG(?c) AS ?avg_cnt) WHERE {
      {
        SELECT ?d (COUNT(DISTINCT ?p) AS ?c) WHERE {
          GRAPH <urn:hpoa> {
            ?d hpoa:has_phenotype ?p .
          }
        } GROUP BY ?d
      }
    }
  }
  FILTER(?cnt > ?avg_cnt)
} ORDER BY DESC(?cnt)
LIMIT 20

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?phenotype_label (COUNT(DISTINCT ?disease) AS ?freq) WHERE {
  {
    SELECT DISTINCT ?omim_id WHERE {
      GRAPH <urn:doid> {
        ?doid_class rdfs:subClassOf+ obo:DOID_417 ;
                    oboInOwl:hasDbXref ?xref .
        FILTER(STRSTARTS(STR(?xref), "MIM:"))
      }
      BIND(REPLACE(STR(?xref), "^MIM:", "OMIM:") AS ?omim_id)
    }
  }
  GRAPH <urn:hpoa> {
    ?disease hpoa:source_id ?omim_id ;
             hpoa:has_phenotype ?pheno .
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:label ?phenotype_label .
  }
} GROUP BY ?pheno ?phenotype_label
ORDER BY DESC(?freq)
LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?category_label ?disease_name ?cnt WHERE {
  {
    SELECT ?category ?disease_name (COUNT(DISTINCT ?pheno) AS ?cnt) WHERE {
      GRAPH <urn:hpoa> {
        ?disease hpoa:has_phenotype ?pheno ;
                 rdfs:label ?disease_name .
      }
      GRAPH <urn:hpo> {
        ?pheno rdfs:subClassOf+ ?category .
        ?category rdfs:subClassOf obo:HP_0000118 .
      }
    } GROUP BY ?category ?disease ?disease_name
  }
  {
    SELECT ?category (MAX(?cnt2) AS ?max_cnt) WHERE {
      {
        SELECT ?category ?disease2 (COUNT(DISTINCT ?pheno2) AS ?cnt2) WHERE {
          GRAPH <urn:hpoa> {
            ?disease2 hpoa:has_phenotype ?pheno2 .
          }
          GRAPH <urn:hpo> {
            ?pheno2 rdfs:subClassOf+ ?category .
            ?category rdfs:subClassOf obo:HP_0000118 .
          }
        } GROUP BY ?category ?disease2
      }
    } GROUP BY ?category
  }
  FILTER(?cnt = ?max_cnt)
  GRAPH <urn:hpo> {
    ?category rdfs:label ?category_label .
  }
} ORDER BY DESC(?cnt)

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?phenotype_label ?disease_count WHERE {
  {
    SELECT ?pheno (COUNT(DISTINCT ?disease) AS ?disease_count) WHERE {
      GRAPH <urn:hpoa> {
        ?disease hpoa:has_phenotype ?pheno .
      }
    } GROUP BY ?pheno
    HAVING (COUNT(DISTINCT ?disease) > 50)
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:subClassOf+ obo:HP_0000707 ;
           rdfs:label ?phenotype_label .
  }
} ORDER BY DESC(?disease_count)

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
SELECT ?term ?label WHERE {
  GRAPH <urn:hpo> {
    ?term rdfs:subClassOf+ obo:HP_0001434 ;
          rdfs:label ?label .
  }
} LIMIT 30

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
SELECT DISTINCT ?label WHERE {
  GRAPH <urn:doid> {
    ?disease rdfs:label ?label ;
             (obo:IAO_0000115|oboInOwl:hasExactSynonym) ?text .
