      BIND(REPLACE(STR(?xref), "^MIM:", "OMIM:") AS ?omim_id)
      GRAPH <urn:hpoa> {
        ?disease hpoa:source_id ?omim_id ;
                 hpoa:has_phenotype ?pheno .
      }
    } GROUP BY ?omim_id ?doid_label
    HAVING (COUNT(DISTINCT ?pheno) > 20)
  }
  {
    SELECT ?omim_id2 (COUNT(DISTINCT ?neuro) AS ?neuro_pheno) WHERE {
      GRAPH <urn:doid> {
