    SELECT ?pheno (COUNT(DISTINCT ?disease) AS ?disease_count) WHERE {
      GRAPH <urn:hpoa> {
        ?disease hpoa:has_phenotype ?pheno .
      }
    } GROUP BY ?pheno
    HAVING (COUNT(DISTINCT ?disease) > 50)
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:subClassOf+ obo:HP_0000707 ;
           rdfs:label ?phenotype_label .
  }
} ORDER BY DESC(?disease_count)

