PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?category_label (COUNT(DISTINCT ?pheno) AS ?pheno_count) WHERE {
  GRAPH <urn:hpoa> {
    ?disease hpoa:has_phenotype ?pheno .
  }
  GRAPH <urn:hpo> {
    ?pheno rdfs:subClassOf+ ?category .
    ?category rdfs:subClassOf obo:HP_0000118 ;
              rdfs:label ?category_label .
  }
} GROUP BY ?category ?category_label
HAVING (COUNT(DISTINCT ?pheno) > 100)
ORDER BY DESC(?pheno_count)

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX oboInOwl: <http://www.geneontology.org/formats/oboInOwl#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?doid_label ?total_pheno ?neuro_pheno WHERE {
  {
    SELECT ?omim_id ?doid_label (COUNT(DISTINCT ?pheno) AS ?total_pheno) WHERE {
      GRAPH <urn:doid> {
        ?doid_class rdfs:subClassOf+ obo:DOID_630 ;
                    rdfs:label ?doid_label ;
                    oboInOwl:hasDbXref ?xref .
        FILTER(STRSTARTS(STR(?xref), "MIM:"))
      }
      BIND(REPLACE(STR(?xref), "^MIM:", "OMIM:") AS ?omim_id)
      GRAPH <urn:hpoa> {
        ?disease hpoa:source_id ?omim_id ;
                 hpoa:has_phenotype ?pheno .
      }
    } GROUP BY ?omim_id ?doid_label
    HAVING (COUNT(DISTINCT ?pheno) > 20)
  }
  {
    SELECT ?omim_id2 (COUNT(DISTINCT ?neuro) AS ?neuro_pheno) WHERE {
      GRAPH <urn:doid> {
        ?dc oboInOwl:hasDbXref ?xr .
        FILTER(STRSTARTS(STR(?xr), "MIM:"))
      }
      BIND(REPLACE(STR(?xr), "^MIM:", "OMIM:") AS ?omim_id2)
      GRAPH <urn:hpoa> {
        ?d2 hpoa:source_id ?omim_id2 ;
            hpoa:has_phenotype ?neuro .
      }
      GRAPH <urn:hpo> {
        ?neuro rdfs:subClassOf+ obo:HP_0000707 .
      }
    } GROUP BY ?omim_id2
    HAVING (COUNT(DISTINCT ?neuro) > 5)
  }
  FILTER(?omim_id = ?omim_id2)
} ORDER BY DESC(?total_pheno)
LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX hpoa: <http://example.org/hpoa/>
SELECT ?disease1_name ?disease2_name (COUNT(DISTINCT ?pheno) AS ?shared_phenotypes) WHERE {
  GRAPH <urn:hpoa> {
    ?d1 hpoa:has_phenotype ?pheno ;
        rdfs:label ?disease1_name ;
        hpoa:source_id ?sid1 .
    ?d2 hpoa:has_phenotype ?pheno ;
        rdfs:label ?disease2_name ;
        hpoa:source_id ?sid2 .
    FILTER(STR(?sid1) < STR(?sid2))
  }
} GROUP BY ?d1 ?d2 ?disease1_name ?disease2_name
HAVING (COUNT(DISTINCT ?pheno) > 10)
ORDER BY DESC(?shared_phenotypes)
LIMIT 20
